#include <stdio.h>
int main() {
    int T; if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        long long X, Y, M;
        scanf("%lld %lld %lld", &X, &Y, &M);
        long long rent = X * M;
        if (rent < Y) printf("YES\n");
        else printf("NO\n");
    }
    return 0;
}

